mapper.select:
SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS date, COUNT(*) AS count, department, registration_type AS registrationType, IFNULL(SUM(registration_fee), 0) AS totalFee FROM registration WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
AND department = #{department}
GROUP BY date, department, registration_type ORDER BY date DESC
